module top_module( output reg [15:0] A_Data, B_Data, input [15:0] D_Data, input [2:0] AA, BA, DA, input RW, CLK );reg [15:0] unused_REGS[7:0];

always@(posedge CLK)
	if(RW)
		case(DA)
		    3'b 000 : unused_REGS[0] = D_Data;
			 3'b 001 : unused_REGS[1] = D_Data;
			 3'b 010 : unused_REGS[2] = D_Data;
			 3'b 011 : unused_REGS[3] = D_Data;
			 3'b 100 : unused_REGS[4] = D_Data;
			 3'b 101 : unused_REGS[5] = D_Data;
			 3'b 110 : unused_REGS[6] = D_Data;
			 3'b 111 : unused_REGS[7] = D_Data;
		endcase

always@(*)
	begin
		case(AA)
		    3'b 000 : A_Data = unused_REGS[0];
			 3'b 001 : A_Data = unused_REGS[1];
			 3'b 010 : A_Data = unused_REGS[2];
			 3'b 011 : A_Data = unused_REGS[3];
			 3'b 100 : A_Data = unused_REGS[4];
			 3'b 101 : A_Data = unused_REGS[5];
			 3'b 110 : A_Data = unused_REGS[6];
			 3'b 111 : A_Data = unused_REGS[7];
		endcase

		case(BA)
		    3'b 000 : B_Data = unused_REGS[0];
			 3'b 001 : B_Data = unused_REGS[1];
			 3'b 010 : B_Data = unused_REGS[2];
			 3'b 011 : B_Data = unused_REGS[3];
			 3'b 100 : B_Data = unused_REGS[4];
			 3'b 101 : B_Data = unused_REGS[5];
			 3'b 110 : B_Data = unused_REGS[6];
			 3'b 111 : B_Data = unused_REGS[7];
		endcase
	end

endmodule
